/**
 * Email notification adapter — delivers notifications via email.
 *
 * Responsibilities:
 * 1. Template rendering — maps NotificationType to formatted subject/body
 * 2. Recipient resolution — resolves user IDs to email addresses via UserRepository
 * 3. Delivery — sends email (pluggable transport, defaults to in-memory for dev/test)
 *
 * Implements NotificationAdapter interface. Must not throw — returns failed
 * NotificationResult on errors.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter's SMTP/transport settings.
 */
export interface EmailConfig {
  /** SMTP host or email service endpoint */
  host: string;
  /** SMTP port */
  port: number;
  /** Sender email address */
  from: string;
  /** Reply-to address (optional, defaults to from) */
  replyTo?: string;
}

export const defaultEmailConfig: EmailConfig = {
  host: 'localhost',
  port: 587,
  from: 'noreply@taskflowpro.example',
};

/**
 * A rendered email ready for delivery.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  replyTo: string;
  subject: string;
  text: string;
  html: string;
}

/**
 * Transport interface for pluggable email delivery.
 * Implement this to swap in a real SMTP/SES/SendGrid transport.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * In-memory transport for development and testing.
 * Stores all sent emails for inspection.
 */
export class InMemoryEmailTransport implements EmailTransport {
  private inbox: Array<RenderedEmail & { messageId: string }> = [];

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    const messageId = `msg-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.inbox.push({ ...email, messageId });
    return { messageId };
  }

  getInbox(): Array<RenderedEmail & { messageId: string }> {
    return [...this.inbox];
  }

  clear(): void {
    this.inbox = [];
  }
}

