/**
 * Minimal HTML escaping to prevent XSS in email templates.
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Recipient resolver function type.
 * Given a recipient string (which may be a user ID or email),
 * returns a resolved { email, name } or undefined if unresolvable.
 */
export type RecipientResolver = (
  recipient: string,
) => { email: string; name: string } | undefined;

/**
 * Default resolver — treats the recipient string as an email address directly.
 */
function defaultRecipientResolver(recipient: string): { email: string; name: string } | undefined {
  if (recipient.includes('@')) {
    return { email: recipient, name: recipient.split('@')[0] ?? recipient };
  }
  return undefined;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private recipientResolver: RecipientResolver;
  private config: EmailConfig;

  constructor(options?: {
    config?: EmailConfig;
    transport?: EmailTransport;
    recipientResolver?: RecipientResolver;
  }) {
    this.config = options?.config ?? defaultEmailConfig;
    this.transport = options?.transport ?? new InMemoryEmailTransport();
    this.recipientResolver = options?.recipientResolver ?? defaultRecipientResolver;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Step 1: Resolve recipient
      const resolved = this.recipientResolver(payload.recipient);
      if (!resolved) {
        this.logger.warn(`Cannot resolve recipient: ${payload.recipient}`);
        return {
          notificationId: payload.id,
          channel: 'email',
          success: false,
          error: `Cannot resolve email for recipient: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Step 2: Render template
      const rendered = this.renderEmail(payload, resolved);

      // Step 3: Send via transport
      this.logger.info(`Sending email to ${resolved.email}: "${rendered.subject}"`);
      const result = await this.transport.sendMail(rendered);
      this.logger.info(`Email delivered: ${payload.id} (messageId: ${result.messageId})`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: true,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email for ${payload.id}: ${message}`);
      return {
        notificationId: payload.id,
        channel: 'email',
        success: false,
        error: `Email delivery failed: ${message}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Render a NotificationPayload into a RenderedEmail using the template
   * for the payload's notification type.
   */
  renderEmail(
    payload: NotificationPayload,
    resolved: { email: string; name: string },
  ): RenderedEmail {
    const template = emailTemplates[payload.type];
    const vars = this.buildTemplateVars(payload, resolved);

    return {
      to: resolved.email,
      from: this.config.from,
      replyTo: this.config.replyTo ?? this.config.from,
      subject: template.subject(vars),
      text: template.text(vars),
      html: template.html(vars),
    };
  }

  /**
   * Build template variables from the payload and its metadata.
   */
  private buildTemplateVars(
    payload: NotificationPayload,
    resolved: { email: string; name: string },
  ): Record<string, string> {
    const metadata = payload.metadata ?? {};
    const vars: Record<string, string> = {
      recipientName: resolved.name,
      recipientEmail: resolved.email,
    };

    // Pull known metadata fields into template vars
    for (const [key, value] of Object.entries(metadata)) {
      if (typeof value === 'string') {
        vars[key] = value;
      } else if (typeof value === 'number') {
        vars[key] = String(value);
      }
    }

    // Extract structured info from payload body/subject as fallback context
    if (!vars['orderId'] && payload.subject) {
      const orderMatch = payload.subject.match(/:\s*(order-\S+)/i);
      if (orderMatch) {
        vars['orderId'] = orderMatch[1]!;
      }
    }

    return vars;
  }

  /**
   * Get the underlying transport (for testing).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  InMemoryEmailTransport,
  defaultEmailConfig,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailTransport,
  RenderedEmail,
  RecipientResolver,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-42',
    body: 'Your order has been placed.',
    priority: 'normal',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('EmailNotificationAdapter', () => {
  let transport: InMemoryEmailTransport;
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    transport = new InMemoryEmailTransport();
    adapter = new EmailNotificationAdapter({ transport });
  });

  it('has channel "email"', () => {
    expect(adapter.channel).toBe('email');
  });

  describe('send', () => {
    it('sends email successfully for a valid recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('delivers email via transport with rendered content', async () => {
      await adapter.send(makePayload());

      const inbox = transport.getInbox();
      expect(inbox).toHaveLength(1);
      expect(inbox[0]!.to).toBe('alice@example.com');
      expect(inbox[0]!.from).toBe(defaultEmailConfig.from);
      expect(inbox[0]!.subject).toContain('Order Confirmation');
      expect(inbox[0]!.html).toContain('<h2>');
      expect(inbox[0]!.text).toContain('order-42');
    });

    it('returns failure when recipient cannot be resolved', async () => {
      const resolver: RecipientResolver = () => undefined;
      const adapterWithResolver = new EmailNotificationAdapter({
        transport,
        recipientResolver: resolver,
      });

      const result = await adapterWithResolver.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve email');
      expect(transport.getInbox()).toHaveLength(0);
    });

    it('returns failure when transport throws', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };
      const adapterWithFailing = new EmailNotificationAdapter({
        transport: failingTransport,
      });

      const result = await adapterWithFailing.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMTP connection refused');
    });

    it('never throws, even on unexpected errors', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw 'string error';
        },
      };
      const adapterWithFailing = new EmailNotificationAdapter({
        transport: failingTransport,
      });

      const result = await adapterWithFailing.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });
  });

  describe('recipient resolution', () => {
    it('resolves email addresses directly by default', async () => {
      const result = await adapter.send(
        makePayload({ recipient: 'bob@example.com' }),
      );
      expect(result.success).toBe(true);
      expect(transport.getInbox()[0]!.to).toBe('bob@example.com');
    });

    it('uses custom recipient resolver', async () => {
      const resolver: RecipientResolver = (recipient) => {
        if (recipient === 'user-1') {
          return { email: 'resolved@example.com', name: 'Resolved User' };
        }
        return undefined;
      };
      const adapterWithResolver = new EmailNotificationAdapter({
        transport,
        recipientResolver: resolver,
      });

      const result = await adapterWithResolver.send(
        makePayload({ recipient: 'user-1' }),
      );

      expect(result.success).toBe(true);
      expect(transport.getInbox()[0]!.to).toBe('resolved@example.com');
      expect(transport.getInbox()[0]!.text).toContain('Resolved User');
    });

    it('fails for non-email recipients without custom resolver', async () => {
      const result = await adapter.send(
        makePayload({ recipient: 'user-123' }),
      );
      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve email');
    });
  });

  describe('template rendering', () => {
    it('renders order-confirmation template', () => {
      const payload = makePayload({
        type: 'order-confirmation',
        metadata: { orderId: 'order-99', items: 'Widget x2', total: '$50.00' },
      });
      const rendered = adapter.renderEmail(payload, {
        email: 'alice@example.com',
        name: 'Alice',
      });

      expect(rendered.subject).toBe('Order Confirmation: order-99');
      expect(rendered.text).toContain('Hi Alice');
      expect(rendered.text).toContain('order-99');
      expect(rendered.text).toContain('Widget x2');
      expect(rendered.text).toContain('$50.00');
      expect(rendered.html).toContain('<h2>Order Confirmation</h2>');
    });

    it('renders order-status-update template', () => {
      const payload = makePayload({
        type: 'order-status-update',
        metadata: {
          orderId: 'order-5',
          previousStatus: 'pending',
          newStatus: 'shipped',
        },
      });
      const rendered = adapter.renderEmail(payload, {
        email: 'bob@example.com',
        name: 'Bob',
      });

      expect(rendered.subject).toContain('order-5');
      expect(rendered.text).toContain('pending');
      expect(rendered.text).toContain('shipped');
      expect(rendered.html).toContain('pending');
      expect(rendered.html).toContain('shipped');
    });

    it('renders welcome template', () => {
      const payload = makePayload({ type: 'welcome' });
      const rendered = adapter.renderEmail(payload, {
        email: 'carol@example.com',
        name: 'Carol',
      });

      expect(rendered.subject).toBe('Welcome to TaskFlow Pro');
      expect(rendered.text).toContain('Hi Carol');
      expect(rendered.html).toContain('Carol');
    });

    it('renders account-updated template', () => {
      const payload = makePayload({ type: 'account-updated' });
      const rendered = adapter.renderEmail(payload, {
        email: 'dave@example.com',
        name: 'Dave',
      });

      expect(rendered.subject).toBe('Your Account Has Been Updated');
      expect(rendered.text).toContain('Dave');
      expect(rendered.text).toContain('contact support');
    });

    it('escapes HTML in template variables', () => {
      const payload = makePayload({
        type: 'welcome',
      });
      const rendered = adapter.renderEmail(payload, {
        email: 'test@example.com',
        name: '<script>alert("xss")</script>',
      });

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });

    it('sets from and replyTo from config', () => {
      const customAdapter = new EmailNotificationAdapter({
        transport,
        config: {
          host: 'smtp.example.com',
          port: 465,
          from: 'sender@example.com',
          replyTo: 'support@example.com',
        },
      });

      const rendered = customAdapter.renderEmail(makePayload(), {
        email: 'alice@example.com',
        name: 'Alice',
      });

      expect(rendered.from).toBe('sender@example.com');
      expect(rendered.replyTo).toBe('support@example.com');
    });

    it('defaults replyTo to from address', () => {
      const rendered = adapter.renderEmail(makePayload(), {
        email: 'alice@example.com',
        name: 'Alice',
      });

      expect(rendered.replyTo).toBe(defaultEmailConfig.from);
    });

    it('extracts orderId from subject when not in metadata', () => {
      const payload = makePayload({
        type: 'order-confirmation',
        subject: 'Order Confirmation: order-77',
        metadata: {},
      });
      const rendered = adapter.renderEmail(payload, {
        email: 'alice@example.com',
        name: 'Alice',
      });

      expect(rendered.subject).toContain('order-77');
      expect(rendered.text).toContain('order-77');
    });
  });

  describe('InMemoryEmailTransport', () => {
    it('stores sent emails', async () => {
      const t = new InMemoryEmailTransport();
      const email: RenderedEmail = {
        to: 'test@example.com',
        from: 'sender@example.com',
        replyTo: 'sender@example.com',
        subject: 'Test',
        text: 'Hello',
        html: '<p>Hello</p>',
      };

      const result = await t.sendMail(email);

      expect(result.messageId).toBeTruthy();
      expect(t.getInbox()).toHaveLength(1);
      expect(t.getInbox()[0]!.to).toBe('test@example.com');
    });

    it('clears inbox', async () => {
      const t = new InMemoryEmailTransport();
      await t.sendMail({
        to: 'a@b.com',
        from: 'x@y.com',
        replyTo: 'x@y.com',
        subject: 's',
        text: 't',
        html: 'h',
      });

      t.clear();
      expect(t.getInbox()).toHaveLength(0);
    });
  });
});
